     1→/**
     2→ * MMS Demo CSV Import Module
     3→ *
     4→ * Parses client-provided CSV files (Maximo exports) for the application.
     5→ * Supports Fleet Roster, PM History, and PM Rules CSVs per spec 009 Section 9.2.1.
     6→ *
     7→ * @example
     8→ * ```typescript
     9→ * import { parseFleetRosterCsv, parsePmHistoryCsv, importDemoData } from './csv-import';
    10→ *
    11→ * // Parse individual CSV strings
    12→ * const roster = parseFleetRosterCsv(csvContent);
    13→ * const history = parsePmHistoryCsv(csvContent);
    14→ *
    15→ * // Import complete demo data from multiple CSVs
    16→ * const demoData = importDemoData({
    17→ *   fleetRoster: rosterCsv,
    18→ *   pmHistory: historyCsv,
    19→ *   pmRules: rulesCsv, // optional, uses defaults if not provided
    20→ * });
    21→ * ```
    22→ *
    23→ * @see specs/009-demo-application.md Section 9.2.1
    24→ */
    25→
    26→import * as Papa from 'papaparse';
    27→import {
    28→  parseFleetRosterCsvRow,
    29→  isValidDateString,
    30→  type ValidationError,
    31→} from '../lib/schemas';
    32→import { PM_RULES_BY_FLEET } from './data';
    33→
    34→// =============================================================================
    35→// Types
    36→// =============================================================================
    37→
    38→/** Imported train from Fleet Roster CSV */
    39→export interface ImportedTrain {
    40→  trainNumber: string;
    41→  fleetCode: string;
    42→  currentMileageKm: number;
    43→  commissioningDate: Date;
    44→  estimatedDailyKm: number;
    45→  confidence: 'HISTORICAL' | 'ESTIMATED';
    46→}
    47→
    48→/** Imported PM history record */
    49→export interface ImportedPMHistory {
    50→  trainNumber: string;
    51→  pmCode: string;
    52→  completionDate: Date;
    53→  mileageAtCompletion: number;
    54→}
    55→
    56→/** Imported PM rule */
    57→export interface ImportedPMRule {
    58→  fleetCode: string;
    59→  pmCode: string;
    60→  intervalKm: number;
    61→  intervalMonths: number | null;
    62→  durationDays: number;
    63→  estimatedHours: number;
    64→  satisfiesCodes: string[];
    65→}
    66→
    67→/** Complete fleet state from imported data */
    68→export interface FleetState {
    69→  trains: ImportedTrain[];
    70→  pmHistory: ImportedPMHistory[];
    71→  pmRules: ImportedPMRule[];
    72→}
    73→
    74→/** CSV parse result with detailed errors */
    75→export interface CsvParseResult<T> {
    76→  success: boolean;
    77→  data: T[];
    78→  errors: CsvParseError[];
    79→  warnings: string[];
    80→  stats: {
    81→    totalRows: number;
    82→    validRows: number;
    83→    invalidRows: number;
    84→    duplicatesRemoved: number;
    85→  };
    86→}
    87→
    88→/** Detailed parse error with row information */
    89→export interface CsvParseError {
    90→  row: number;
    91→  field: string;
    92→  message: string;
    93→  rawValue?: string;
    94→}
    95→
    96→/** Import options for customizing behavior */
    97→export interface ImportOptions {
    98→  /** Throw on first error (default: false, collect all errors) */
    99→  strict?: boolean;
   100→  /** Default commissioning date if not provided (default: 5 years ago) */
   101→  defaultCommissioningDate?: Date;
   102→  /** Daily km estimate if no PM history exists (default: 150 km/day) */
   103→  defaultDailyKm?: number;
   104→}
   105→
   106→// =============================================================================
   107→// Constants
   108→// =============================================================================
   109→
   110→/** Default daily km for trains without history */
   111→const DEFAULT_DAILY_KM = 150;
   112→
   113→/** Minimum commissioning date (sanity check) */
   114→const MIN_COMMISSIONING_DATE = new Date('2000-01-01');
   115→
   116→/** Valid PM codes per spec */
   117→const VALID_PM_CODES = ['C1', 'C2', 'C3', 'C4', 'C5', 'OH'];
   118→
   119→// =============================================================================
   120→// Fleet Roster CSV Parser
   121→// =============================================================================
   122→
   123→/**
   124→ * Parse Fleet Roster CSV content
   125→ *
   126→ * Expected columns:
   127→ * - train_number (required): Unique train identifier
   128→ * - fleet_code (required): Fleet type (e.g., "KS", "ALSTOM")
   129→ * - current_mileage_km (required): Current odometer reading
   130→ * - commissioning_date (optional): YYYY-MM-DD format
   131→ *
   132→ * Validation rules per spec 009:
   133→ * - train_number must be unique
   134→ * - current_mileage_km must be > 0
   135→ * - commissioning_date must be in the past
   136→ */
   137→export function parseFleetRosterCsv(
   138→  csvContent: string,
   139→  options: ImportOptions = {}
   140→): CsvParseResult<ImportedTrain> {
   141→  const result: CsvParseResult<ImportedTrain> = {
   142→    success: true,
   143→    data: [],
   144→    errors: [],
   145→    warnings: [],
   146→    stats: { totalRows: 0, validRows: 0, invalidRows: 0, duplicatesRemoved: 0 },
   147→  };
   148→
   149→  const defaultDate =
   150→    options.defaultCommissioningDate ??
   151→    new Date(Date.now() - 5 * 365 * 24 * 60 * 60 * 1000); // 5 years ago
   152→
   153→  const parsed = Papa.parse<Record<string, string>>(csvContent, {
   154→    header: true,
   155→    skipEmptyLines: true,
   156→    transformHeader: (header) => header.trim().toLowerCase(),
   157→  });
   158→
   159→  if (parsed.errors.length > 0) {
   160→    for (const err of parsed.errors) {
   161→      result.errors.push({
   162→        row: err.row ?? 0,
   163→        field: 'csv',
   164→        message: err.message,
   165→      });
   166→    }
   167→    if (options.strict) {
   168→      result.success = false;
   169→      return result;
   170→    }
   171→  }
   172→
   173→  const seenTrainNumbers = new Set<string>();
   174→  result.stats.totalRows = parsed.data.length;
   175→
   176→  for (let i = 0; i < parsed.data.length; i++) {
   177→    const row = parsed.data[i];
   178→    const rowNum = i + 2; // +2 for header row and 0-based index
   179→
   180→    const parseResult = parseFleetRosterCsvRow(row);
   181→
   182→    if (!parseResult.success) {
   183→      result.stats.invalidRows++;
   184→      for (const err of parseResult.errors) {
   185→        result.errors.push({
   186→          row: rowNum,
   187→          field: err.field,
   188→          message: err.message,
   189→          rawValue: String(row[err.field] ?? ''),
   190→        });
   191→      }
   192→      if (options.strict) {
   193→        result.success = false;
   194→        return result;
   195→      }
   196→      continue;
   197→    }
   198→
   199→    const data = parseResult.data;
   200→
   201→    // Check for duplicate train numbers
   202→    if (seenTrainNumbers.has(data.trainNumber)) {
   203→      result.warnings.push(
   204→        `Row ${rowNum}: Duplicate train number '${data.trainNumber}' - keeping first occurrence`
   205→      );
   206→      result.stats.duplicatesRemoved++;
   207→      continue;
   208→    }
   209→    seenTrainNumbers.add(data.trainNumber);
   210→
   211→    // Validate mileage > 0
   212→    if (data.currentMileageKm <= 0) {
   213→      result.errors.push({
   214→        row: rowNum,
   215→        field: 'current_mileage_km',
   216→        message: 'Mileage must be greater than 0',
   217→        rawValue: String(data.currentMileageKm),
   218→      });
   219→      result.stats.invalidRows++;
   220→      if (options.strict) {
   221→        result.success = false;
   222→        return result;
   223→      }
   224→      continue;
   225→    }
   226→
   227→    // Parse commissioning date
   228→    let commissioningDate: Date;
   229→    if (data.commissioningDate && isValidDateString(data.commissioningDate)) {
   230→      commissioningDate = new Date(data.commissioningDate);
   231→
   232→      // Validate commissioning date is in the past
   233→      if (commissioningDate > new Date()) {
   234→        result.errors.push({
   235→          row: rowNum,
   236→          field: 'commissioning_date',
   237→          message: 'Commissioning date must be in the past',
   238→          rawValue: data.commissioningDate,
   239→        });
   240→        result.stats.invalidRows++;
   241→        if (options.strict) {
   242→          result.success = false;
   243→          return result;
   244→        }
   245→        continue;
   246→      }
   247→
   248→      // Sanity check: not before 2000
   249→      if (commissioningDate < MIN_COMMISSIONING_DATE) {
   250→        result.warnings.push(
   251→          `Row ${rowNum}: Unusually early commissioning date '${data.commissioningDate}'`
   252→        );
   253→      }
   254→    } else {
   255→      commissioningDate = defaultDate;
   256→      result.warnings.push(
   257→        `Row ${rowNum}: Missing commissioning date, using default (${defaultDate.toISOString().split('T')[0]})`
   258→      );
   259→    }
   260→
   261→    result.data.push({
   262→      trainNumber: data.trainNumber,
   263→      fleetCode: data.fleetCode.toUpperCase(),
   264→      currentMileageKm: data.currentMileageKm,
   265→      commissioningDate,
   266→      estimatedDailyKm: options.defaultDailyKm ?? DEFAULT_DAILY_KM,
   267→      confidence: 'ESTIMATED',
   268→    });
   269→    result.stats.validRows++;
   270→  }
   271→
   272→  result.success = result.stats.invalidRows === 0 || !options.strict;
   273→  return result;
   274→}
   275→
   276→// =============================================================================
   277→// PM History CSV Parser
   278→// =============================================================================
   279→
   280→/**
   281→ * Parse PM History CSV content
   282→ *
   283→ * Expected columns (per spec 009):
   284→ * - train_number (required): References fleet roster
   285→ * - pm_code (required): PM type (C1, C2, C3, C4, C5, OH)
   286→ * - completion_date (required): YYYY-MM-DD format
   287→ * - mileage_at_completion (optional but recommended): Odometer at completion
   288→ *
   289→ * Validation rules per spec 009:
   290→ * - train_number should exist in fleet roster (warning if not)
   291→ * - pm_code must be valid (C1-C5, OH)
   292→ * - mileage_at_completion must be > 0 (discard zeros)
   293→ * - Deduplicate by (train_number, pm_code, completion_date)
   294→ */
   295→export function parsePmHistoryCsv(
   296→  csvContent: string,
   297→  fleetTrainNumbers?: Set<string>,
   298→  options: ImportOptions = {}
   299→): CsvParseResult<ImportedPMHistory> {
   300→  const result: CsvParseResult<ImportedPMHistory> = {
   301→    success: true,
   302→    data: [],
   303→    errors: [],
   304→    warnings: [],
   305→    stats: { totalRows: 0, validRows: 0, invalidRows: 0, duplicatesRemoved: 0 },
   306→  };
   307→
   308→  const parsed = Papa.parse<Record<string, string>>(csvContent, {
   309→    header: true,
   310→    skipEmptyLines: true,
   311→    transformHeader: (header) => header.trim().toLowerCase(),
   312→  });
   313→
   314→  if (parsed.errors.length > 0) {
   315→    for (const err of parsed.errors) {
   316→      result.errors.push({
   317→        row: err.row ?? 0,
   318→        field: 'csv',
   319→        message: err.message,
   320→      });
   321→    }
   322→    if (options.strict) {
   323→      result.success = false;
   324→      return result;
   325→    }
   326→  }
   327→
   328→  const seenKeys = new Set<string>();
   329→  result.stats.totalRows = parsed.data.length;
   330→
   331→  for (let i = 0; i < parsed.data.length; i++) {
   332→    const row = parsed.data[i];
   333→    const rowNum = i + 2;
   334→
   335→    // Extract fields directly per spec 009 column names
   336→    const trainNumber = (row['train_number'] ?? '').trim();
   337→    const pmCode = (row['pm_code'] ?? '').trim().toUpperCase();
   338→    const completionDateStr = (row['completion_date'] ?? '').trim();
   339→    // Handle both spec 009 name and lib/schemas name
   340→    const mileageStr = (row['mileage_at_completion'] ?? row['completion_mileage_km'] ?? '').trim();
   341→
   342→    const errors: ValidationError[] = [];
   343→
   344→    if (!trainNumber) {
   345→      errors.push({ field: 'train_number', message: 'Train number required' });
   346→    }
   347→
   348→    if (!pmCode) {
   349→      errors.push({ field: 'pm_code', message: 'PM code required' });
   350→    } else if (!VALID_PM_CODES.includes(pmCode)) {
   351→      errors.push({
   352→        field: 'pm_code',
   353→        message: `Invalid PM code '${pmCode}'. Must be one of: ${VALID_PM_CODES.join(', ')}`,
   354→      });
   355→    }
   356→
   357→    if (!isValidDateString(completionDateStr)) {
   358→      errors.push({ field: 'completion_date', message: 'Date must be in YYYY-MM-DD format' });
   359→    }
   360→
   361→    const mileageAtCompletion = mileageStr ? parseInt(mileageStr, 10) : 0;
   362→    if (mileageStr && isNaN(mileageAtCompletion)) {
   363→      errors.push({ field: 'mileage_at_completion', message: 'Mileage must be a number' });
   364→    }
   365→
   366→    if (errors.length > 0) {
   367→      result.stats.invalidRows++;
   368→      for (const err of errors) {
   369→        result.errors.push({
   370→          row: rowNum,
   371→          field: err.field,
   372→          message: err.message,
   373→          rawValue: String(row[err.field] ?? ''),
   374→        });
   375→      }
   376→      if (options.strict) {
   377→        result.success = false;
   378→        return result;
   379→      }
   380→      continue;
   381→    }
   382→
   383→    // Check if train exists in fleet (warning only)
   384→    if (fleetTrainNumbers && !fleetTrainNumbers.has(trainNumber)) {
   385→      result.warnings.push(
   386→        `Row ${rowNum}: Train '${trainNumber}' not found in fleet roster`
   387→      );
   388→    }
   389→
   390→    // Skip zero mileage entries per spec
   391→    if (mileageAtCompletion === 0 && mileageStr !== '') {
   392→      result.warnings.push(
   393→        `Row ${rowNum}: Skipping PM history with zero mileage for train '${trainNumber}'`
   394→      );
   395→      result.stats.duplicatesRemoved++;
   396→      continue;
   397→    }
   398→
   399→    // Deduplicate by (train_number, pm_code, completion_date)
   400→    const dedupeKey = `${trainNumber}|${pmCode}|${completionDateStr}`;
   401→    if (seenKeys.has(dedupeKey)) {
   402→      result.warnings.push(
   403→        `Row ${rowNum}: Duplicate entry for train '${trainNumber}' ${pmCode} on ${completionDateStr} - keeping first`
   404→      );
   405→      result.stats.duplicatesRemoved++;
   406→      continue;
   407→    }
   408→    seenKeys.add(dedupeKey);
   409→
   410→    result.data.push({
   411→      trainNumber,
   412→      pmCode,
   413→      completionDate: new Date(completionDateStr),
   414→      mileageAtCompletion,
   415→    });
   416→    result.stats.validRows++;
   417→  }
   418→
   419→  result.success = result.stats.invalidRows === 0 || !options.strict;
   420→  return result;
   421→}
   422→
   423→// =============================================================================
   424→// PM Rules CSV Parser
   425→// =============================================================================
   426→
   427→/**
   428→ * Parse PM Rules CSV content (optional - defaults exist)
   429→ *
   430→ * Expected columns:
   431→ * - fleet_code (required): Fleet type
   432→ * - pm_code (required): PM type
   433→ * - interval_km (required): Mileage trigger threshold
   434→ * - interval_months (optional): Calendar trigger
   435→ * - duration_days (required): Days train is out of service
   436→ * - estimated_hours (required): Labor hours
   437→ * - satisfies_codes (optional): Comma-separated lower PMs this satisfies
   438→ */
   439→export function parsePmRulesCsv(
   440→  csvContent: string,
   441→  options: ImportOptions = {}
   442→): CsvParseResult<ImportedPMRule> {
   443→  const result: CsvParseResult<ImportedPMRule> = {
   444→    success: true,
   445→    data: [],
   446→    errors: [],
   447→    warnings: [],
   448→    stats: { totalRows: 0, validRows: 0, invalidRows: 0, duplicatesRemoved: 0 },
   449→  };
   450→
   451→  const parsed = Papa.parse<Record<string, string>>(csvContent, {
   452→    header: true,
   453→    skipEmptyLines: true,
   454→    transformHeader: (header) => header.trim().toLowerCase(),
   455→  });
   456→
   457→  if (parsed.errors.length > 0) {
   458→    for (const err of parsed.errors) {
   459→      result.errors.push({
   460→        row: err.row ?? 0,
   461→        field: 'csv',
   462→        message: err.message,
   463→      });
   464→    }
   465→    if (options.strict) {
   466→      result.success = false;
   467→      return result;
   468→    }
   469→  }
   470→
   471→  const seenKeys = new Set<string>();
   472→  result.stats.totalRows = parsed.data.length;
   473→
   474→  for (let i = 0; i < parsed.data.length; i++) {
   475→    const row = parsed.data[i];
   476→    const rowNum = i + 2;
   477→
   478→    const fleetCode = (row['fleet_code'] ?? '').trim().toUpperCase();
   479→    const pmCode = (row['pm_code'] ?? '').trim().toUpperCase();
   480→    const intervalKmStr = (row['interval_km'] ?? '').trim();
   481→    const intervalMonthsStr = (row['interval_months'] ?? '').trim();
   482→    const durationDaysStr = (row['duration_days'] ?? '').trim();
   483→    const estimatedHoursStr = (row['estimated_hours'] ?? '').trim();
   484→    const satisfiesCodesStr = (row['satisfies_codes'] ?? '').trim();
   485→
   486→    const errors: ValidationError[] = [];
   487→
   488→    if (!fleetCode) {
   489→      errors.push({ field: 'fleet_code', message: 'Fleet code required' });
   490→    }
   491→    if (!VALID_PM_CODES.includes(pmCode)) {
   492→      errors.push({
   493→        field: 'pm_code',
   494→        message: `Invalid PM code. Must be one of: ${VALID_PM_CODES.join(', ')}`,
   495→      });
   496→    }
   497→
   498→    const intervalKm = parseInt(intervalKmStr, 10);
   499→    if (isNaN(intervalKm) || intervalKm <= 0) {
   500→      errors.push({ field: 'interval_km', message: 'Interval km must be positive' });
   501→    }
   502→
   503→    const intervalMonths = intervalMonthsStr ? parseInt(intervalMonthsStr, 10) : null;
   504→    if (intervalMonthsStr && (isNaN(intervalMonths!) || intervalMonths! <= 0)) {
   505→      errors.push({ field: 'interval_months', message: 'Interval months must be positive' });
   506→    }
   507→
   508→    const durationDays = parseInt(durationDaysStr, 10);
   509→    if (isNaN(durationDays) || durationDays <= 0) {
   510→      errors.push({ field: 'duration_days', message: 'Duration days must be positive' });
   511→    }
   512→
   513→    const estimatedHours = parseInt(estimatedHoursStr, 10);
   514→    if (isNaN(estimatedHours) || estimatedHours <= 0) {
   515→      errors.push({ field: 'estimated_hours', message: 'Estimated hours must be positive' });
   516→    }
   517→
   518→    if (errors.length > 0) {
   519→      result.stats.invalidRows++;
   520→      for (const err of errors) {
   521→        result.errors.push({
   522→          row: rowNum,
   523→          field: err.field,
   524→          message: err.message,
   525→          rawValue: String(row[err.field] ?? ''),
   526→        });
   527→      }
   528→      if (options.strict) {
   529→        result.success = false;
   530→        return result;
   531→      }
   532→      continue;
   533→    }
   534→
   535→    // Deduplicate by (fleet_code, pm_code)
   536→    const dedupeKey = `${fleetCode}|${pmCode}`;
   537→    if (seenKeys.has(dedupeKey)) {
   538→      result.warnings.push(
   539→        `Row ${rowNum}: Duplicate rule for ${fleetCode} ${pmCode} - keeping first`
   540→      );
   541→      result.stats.duplicatesRemoved++;
   542→      continue;
   543→    }
   544→    seenKeys.add(dedupeKey);
   545→
   546→    // Parse satisfies_codes
   547→    const satisfiesCodes = satisfiesCodesStr
   548→      ? satisfiesCodesStr
   549→          .split(',')
   550→          .map((c) => c.trim().toUpperCase())
   551→          .filter((c) => VALID_PM_CODES.includes(c))
   552→      : [];
   553→
   554→    result.data.push({
   555→      fleetCode,
   556→      pmCode,
   557→      intervalKm,
   558→      intervalMonths,
   559→      durationDays,
   560→      estimatedHours,
   561→      satisfiesCodes,
   562→    });
   563→    result.stats.validRows++;
   564→  }
   565→
   566→  result.success = result.stats.invalidRows === 0 || !options.strict;
   567→  return result;
   568→}
   569→
   570→// =============================================================================
   571→// High-Level Import Function
   572→// =============================================================================
   573→
   574→/** Input for complete demo data import */
   575→export interface DemoImportInput {
   576→  fleetRoster: string;
   577→  pmHistory: string;
   578→  pmRules?: string;
   579→}
   580→
   581→/** Result of complete demo data import */
   582→export interface DemoImportResult {
   583→  success: boolean;
   584→  fleetState: FleetState | null;
   585→  errors: CsvParseError[];
   586→  warnings: string[];
   587→  stats: {
   588→    trains: { valid: number; invalid: number };
   589→    pmHistory: { valid: number; invalid: number };
   590→    pmRules: { valid: number; invalid: number };
   591→  };
   592→}
   593→
   594→/**
   595→ * Import complete demo data from CSV strings
   596→ *
   597→ * This is the main entry point for the demo CSV import feature.
   598→ * Parses Fleet Roster and PM History CSVs, optionally PM Rules.
   599→ *
   600→ * After import, calculates estimated daily km for each train based on PM history.
   601→ */
   602→export function importDemoData(
   603→  input: DemoImportInput,
   604→  options: ImportOptions = {}
   605→): DemoImportResult {
   606→  const result: DemoImportResult = {
   607→    success: true,
   608→    fleetState: null,
   609→    errors: [],
   610→    warnings: [],
   611→    stats: {
   612→      trains: { valid: 0, invalid: 0 },
   613→      pmHistory: { valid: 0, invalid: 0 },
   614→      pmRules: { valid: 0, invalid: 0 },
   615→    },
   616→  };
   617→
   618→  // 1. Parse Fleet Roster
   619→  const rosterResult = parseFleetRosterCsv(input.fleetRoster, options);
   620→  result.errors.push(...rosterResult.errors);
   621→  result.warnings.push(...rosterResult.warnings);
   622→  result.stats.trains = {
   623→    valid: rosterResult.stats.validRows,
   624→    invalid: rosterResult.stats.invalidRows,
   625→  };
   626→
   627→  if (rosterResult.data.length === 0) {
   628→    result.success = false;
   629→    result.errors.push({
   630→      row: 0,
   631→      field: 'fleetRoster',
   632→      message: 'No valid trains found in fleet roster CSV',
   633→    });
   634→    return result;
   635→  }
   636→
   637→  // Build set of train numbers for PM history validation
   638→  const trainNumbers = new Set(rosterResult.data.map((t) => t.trainNumber));
   639→
   640→  // 2. Parse PM History
   641→  const historyResult = parsePmHistoryCsv(input.pmHistory, trainNumbers, options);
   642→  result.errors.push(...historyResult.errors);
   643→  result.warnings.push(...historyResult.warnings);
   644→  result.stats.pmHistory = {
   645→    valid: historyResult.stats.validRows,
   646→    invalid: historyResult.stats.invalidRows,
   647→  };
   648→
   649→  // 3. Parse PM Rules (or use defaults)
   650→  let pmRules: ImportedPMRule[];
   651→
   652→  if (input.pmRules) {
   653→    const rulesResult = parsePmRulesCsv(input.pmRules, options);
   654→    result.errors.push(...rulesResult.errors);
   655→    result.warnings.push(...rulesResult.warnings);
   656→    result.stats.pmRules = {
   657→      valid: rulesResult.stats.validRows,
   658→      invalid: rulesResult.stats.invalidRows,
   659→    };
   660→    pmRules = rulesResult.data;
   661→  } else {
   662→    // Use default PM rules from data.ts
   663→    pmRules = getDefaultPMRules(rosterResult.data);
   664→    result.warnings.push('Using default PM rules (no pm_rules CSV provided)');
   665→    result.stats.pmRules = { valid: pmRules.length, invalid: 0 };
   666→  }
   667→
   668→  // 4. Calculate daily km estimates from PM history
   669→  const trains = calculateDailyEstimates(rosterResult.data, historyResult.data);
   670→
   671→  // 5. Assemble fleet state
   672→  result.fleetState = {
   673→    trains,
   674→    pmHistory: historyResult.data,
   675→    pmRules,
   676→  };
   677→
   678→  result.success = result.errors.length === 0 || !options.strict;
   679→  return result;
   680→}
   681→
   682→// =============================================================================
   683→// Helper Functions
   684→// =============================================================================
   685→
   686→/**
   687→ * Default PM rules for unknown fleet types per spec 009
   688→ * Uses KS (Kawasaki-style) intervals as baseline
   689→ */
   690→const DEFAULT_PM_RULES: Omit<ImportedPMRule, 'fleetCode'>[] = [
   691→  { pmCode: 'C1', intervalKm: 12500, intervalMonths: 6, durationDays: 1, estimatedHours: 8, satisfiesCodes: [] },
   692→  { pmCode: 'C2', intervalKm: 50000, intervalMonths: 24, durationDays: 3, estimatedHours: 24, satisfiesCodes: ['C1'] },
   693→  { pmCode: 'C3', intervalKm: 100000, intervalMonths: 48, durationDays: 7, estimatedHours: 72, satisfiesCodes: ['C1', 'C2'] },
   694→  { pmCode: 'C4', intervalKm: 200000, intervalMonths: 96, durationDays: 14, estimatedHours: 160, satisfiesCodes: ['C1', 'C2', 'C3'] },
   695→  { pmCode: 'C5', intervalKm: 400000, intervalMonths: null, durationDays: 21, estimatedHours: 240, satisfiesCodes: ['C1', 'C2', 'C3', 'C4'] },
   696→  { pmCode: 'OH', intervalKm: 800000, intervalMonths: null, durationDays: 45, estimatedHours: 500, satisfiesCodes: ['C1', 'C2', 'C3', 'C4', 'C5'] },
   697→];
   698→
   699→/**
   700→ * Get default PM rules for the fleets in the roster
   701→ *
   702→ * Uses PM_RULES_BY_FLEET for known fleet codes (ML, AEL, TCL),
   703→ * falls back to DEFAULT_PM_RULES for unknown fleet codes.
   704→ */
   705→function getDefaultPMRules(trains: ImportedTrain[]): ImportedPMRule[] {
   706→  const fleetCodes = new Set(trains.map((t) => t.fleetCode));
   707→  const rules: ImportedPMRule[] = [];
   708→
   709→  for (const fleetCode of fleetCodes) {
   710→    const fleetRules = PM_RULES_BY_FLEET[fleetCode];
   711→    if (fleetRules) {
   712→      for (const rule of fleetRules) {
   713→        rules.push({
   714→          fleetCode,
   715→          pmCode: rule.pmCode,
   716→          intervalKm: rule.intervalKm,
   717→          intervalMonths: rule.intervalMonths || null,
   718→          durationDays: Math.ceil(rule.estimatedHours / 8), // Assume 8h workday
   719→          estimatedHours: rule.estimatedHours,
   720→          satisfiesCodes: rule.satisfiesCodes ?? [],
   721→        });
   722→      }
   723→    } else {
   724→      // Use default rules for unknown fleet codes
   725→      for (const rule of DEFAULT_PM_RULES) {
   726→        rules.push({
   727→          fleetCode,
   728→          ...rule,
   729→        });
   730→      }
   731→    }
   732→  }
   733→
   734→  return rules;
   735→}
   736→
   737→/**
   738→ * Calculate daily km estimates for each train based on PM history
   739→ *
   740→ * Uses recent velocity between last 2 PMs if available,
   741→ * falls back to lifetime average from commissioning.
   742→ *
   743→ * @see specs/009-demo-application.md Section 9.3.1 calculateDailyUtilization
   744→ */
   745→function calculateDailyEstimates(
   746→  trains: ImportedTrain[],
   747→  pmHistory: ImportedPMHistory[]
   748→): ImportedTrain[] {
   749→  // Group PM history by train
   750→  const historyByTrain = new Map<string, ImportedPMHistory[]>();
   751→  for (const pm of pmHistory) {
   752→    const existing = historyByTrain.get(pm.trainNumber) ?? [];
   753→    existing.push(pm);
   754→    historyByTrain.set(pm.trainNumber, existing);
   755→  }
   756→
   757→  return trains.map((train) => {
   758→    const history = historyByTrain.get(train.trainNumber) ?? [];
   759→
   760→    // Filter valid entries and sort by completion date desc
   761→    const validHistory = history
   762→      .filter((h) => h.mileageAtCompletion > 0)
   763→      .sort((a, b) => b.completionDate.getTime() - a.completionDate.getTime());
   764→
   765→    // Try recent velocity between last 2 PMs
   766→    if (validHistory.length >= 2) {
   767→      const recent = validHistory[0];
   768→      const previous = validHistory[1];
   769→      const daysBetween = Math.floor(
   770→        (recent.completionDate.getTime() - previous.completionDate.getTime()) /
   771→          (1000 * 60 * 60 * 24)
   772→      );
   773→      const kmBetween = recent.mileageAtCompletion - previous.mileageAtCompletion;
   774→
   775→      // Sanity checks: at least 14 days between and positive km
   776→      if (daysBetween >= 14 && kmBetween > 0) {
   777→        const rate = kmBetween / daysBetween;
   778→        // Typical metro range: 50-500 km/day
   779→        if (rate > 50 && rate < 500) {
   780→          return {
   781→            ...train,
   782→            estimatedDailyKm: Math.round(rate),
   783→            confidence: 'HISTORICAL' as const,
   784→          };
   785→        }
   786→      }
   787→    }
   788→
   789→    // Fallback: lifetime average from commissioning
   790→    const daysSinceCommission = Math.floor(
   791→      (Date.now() - train.commissioningDate.getTime()) / (1000 * 60 * 60 * 24)
   792→    );
   793→    if (daysSinceCommission > 0 && train.currentMileageKm > 0) {
   794→      const rate = train.currentMileageKm / daysSinceCommission;
   795→      if (rate > 0 && rate < 1000) {
   796→        return {
   797→          ...train,
   798→          estimatedDailyKm: Math.round(rate),
   799→          confidence: 'HISTORICAL' as const,
   800→        };
   801→      }
   802→    }
   803→
   804→    // Last resort: keep default
   805→    return train;
   806→  });
   807→}
   808→
   809→

